GLOSSARY = [
 {"term":"Token","def":"Un pedacito de palabra, la unidad que la IA lee y escribe. Más o menos tres cuartas partes de una palabra.","analogy":"Gasolina en el tanque, cada palabra quema un poco.","n":1},
 {"term":"Límite de uso","def":"Un tope de cuánto puedes usar la IA en cierto tiempo antes de que te haga esperar.","analogy":"Una gasolinera que solo te deja llenar el tanque ciertas veces por hora.","n":1},
 {"term":"Entrada y salida","def":"Lo que envías (entrada) y lo que la IA responde (salida). Las dos queman tokens.","analogy":"Combustible que se quema de ida y de regreso.","n":1},
 {"term":"Ventana de contexto","def":"Todo lo que la IA puede “ver” a la vez en una conversación. Cuando se llena, lo más viejo se cae.","analogy":"Una pizarra que se borra cuando se llena.","n":2},
 {"term":"Instrucción de sistema","def":"Instrucciones fijas que siguen activas toda la conversación, sin importar qué tan larga sea.","analogy":"Escritas con marcador permanente en la pizarra.","n":2},
 {"term":"Gratis vs. pago","def":"La versión gratis es el mismo modelo base; pagar sobre todo desbloquea más límites y funciones extra.","analogy":"Una prueba de manejo vs. rentar el carro.","n":3},
 {"term":"Modelo","def":"El “cerebro” de la IA. Los más nuevos o grandes son más inteligentes, pero pueden ser más lentos o caros.","analogy":"Elegir el vehículo correcto para el viaje.","n":3},
 {"term":"Alucinación","def":"Cuando la IA dice algo falso con total seguridad, porque predice palabras probables, no datos verificados.","analogy":"Un becario seguro de sí mismo que inventa cosas.","n":4},
 {"term":"Prompt","def":"Lo que le escribes a la IA. Entre más específico, mejor el resultado.","analogy":"La receta que le das a tu sous chef.","n":5},
 {"term":"Chat","def":"Una sola conversación, rápida y desechable. No se guarda nada cuando sigues adelante.","analogy":"Una llamada telefónica.","n":6},
 {"term":"Proyecto","def":"Un espacio de trabajo guardado que junta tus archivos, instrucciones fijas y chats de un mismo trabajo.","analogy":"Una oficina dedicada.","n":6},
 {"term":"Artefacto (Canvas)","def":"Un panel junto al chat donde la IA construye algo editable, un documento, una hoja o una mini app.","analogy":"Una mesa de trabajo junto a la conversación.","n":7},
 {"term":"Conexión","def":"Un enlace que deja a la IA entrar a otra app que usas, como correo, calendario o Drive, para traer o actuar.","analogy":"Una llave a otro cuarto.","n":8},
 {"term":"Asistente personalizado (GPT personalizado / Gem)","def":"Un ayudante que armas una vez con instrucciones y ejemplos, y luego reutilizas sin volver a explicar.","analogy":"Un empleado que entrenaste una vez.","n":9},
 {"term":"Instrucciones personalizadas","def":"Preferencias fijas que pones una vez y aplican calladamente a cada chat.","analogy":"Las reglas de la casa pegadas en el refri.","n":10},
 {"term":"Memoria","def":"Unos datos que la IA guarda y carga de un chat al siguiente. Los puedes ver y editar.","analogy":"Una libreta que guarda aparte.","n":11},
 {"term":"Multimodal","def":"IA que maneja imágenes y audio, no solo texto, puedes mostrarle fotos o hablarle.","analogy":"Darle ojos y oídos.","n":12},
 {"term":"Prompt guardado (plantilla)","def":"Una instrucción reutilizable que guardas, a veces con espacios para llenar, y sacas cuando la necesitas.","analogy":"Una receta en tu recetario.","n":13},
 {"term":"Loop","def":"Un trabajo que un agente de IA repite en un horario, se despierta, hace una tarea definida con permisos fijos, anota el resultado y se duerme.","analogy":"Un trabajador en el turno nocturno.","n":14},
 {"term":"Agente","def":"Una IA haciendo una tarea por su cuenta, tomando decisiones y dando pasos hacia una meta, no solo respondiendo una pregunta.","analogy":"Un empleado al que le delegas un trabajo.","n":14},
 {"term":"Vibe coding","def":"Construir software describiendo lo que quieres en lenguaje normal mientras la IA escribe el código.","analogy":"Ser el director, no el albañil.","n":15},
 {"term":"Frontend","def":"La parte de una app que ves y con la que interactúas, diseño, botones, pantallas.","analogy":"El comedor de un restaurante.","n":16},
 {"term":"Backend","def":"El motor tras bambalinas de una app, guardar datos, revisar inicios de sesión, correr la lógica.","analogy":"La cocina de un restaurante.","n":16},
 {"term":"API","def":"El mensajero que deja que dos softwares se hablen, una app le pide algo a otra y recibe respuesta.","analogy":"El mesero entre el comedor y la cocina.","n":17},
 {"term":"Base de datos","def":"Un almacén ordenado de la información de una app, estructurado para encontrar cualquier registro al instante.","analogy":"Un archivero bien etiquetado.","n":18},
 {"term":"Hosting y deployment","def":"El hosting es rentar espacio siempre prendido en internet; el deployment es publicar tu trabajo ahí para que cualquiera lo visite.","analogy":"Rentar un local y luego abrirlo al público.","n":19},
 {"term":"Claude","def":"El asistente de IA de Anthropic, la familia de modelos sobre la que está construido este curso. Bueno para escribir, analizar y razonar con cuidado.","analogy":"Una de las “marcas” de asistente de IA.","n":0},
 {"term":"ChatGPT","def":"El asistente de IA de OpenAI, uno de los más usados, con una versión gratis amplia y muchas funciones extra.","analogy":"Una de las “marcas” de asistente de IA.","n":0},
 {"term":"Gemini","def":"El asistente de IA de Google, integrado en sus productos como Búsqueda, Docs y Gmail.","analogy":"Una de las “marcas” de asistente de IA.","n":0},
 {"term":"Bash","def":"Un “idioma” común para escribir comandos a una computadora por una ventana de texto, en vez de hacer clic en botones.","analogy":"Hablarle a tu computadora con comandos en vez de apuntar y hacer clic.","n":0},
 {"term":"Comando","def":"Una sola instrucción escrita que le das a una computadora en una ventana de texto, una línea que le dice que haga una cosa.","analogy":"Decirle a un trabajador una tarea específica, en voz alta.","n":0},
 {"term":"Terminal (línea de comandos)","def":"La ventana de texto donde escribes comandos directamente a una computadora.","analogy":"La puerta de “solo personal” a la computadora, sin botones, solo instrucciones.","n":0},
 {"term":"Humano al mando (human in the loop)","def":"Mantener a una persona a cargo de dirigir, revisar y responder por el trabajo de la IA, aunque haga más por su cuenta.","analogy":"Un piloto supervisando el piloto automático.","n":20},
]
